i>\r\n\t<li><strong>floor</strong>&nbsp;&ndash; podłoga</li>\r\n\t<li><strong>ceiling</strong>&nbsp;&ndash; sufit</li>\r\n\t<li><strong>wall</strong>&nbsp;&ndash; ściana</li>\r\n\t<li><strong>door</strong>&nbsp;&ndash; drzwi</li>\r\n\t<li><strong>window</strong>&nbsp;&ndash; okno</li>\r\n\t<li><strong>stairs</strong>&nbsp;&ndash; schody</li>\r\n\t<li><strong>roof</strong>&nbsp;&ndash; dach</li>\r\n\t<li><strong>chimney</strong>&nbsp;&ndash; komin</li>\r\n\t<li><strong>fence</strong>&nbsp;&ndash; płot</li>\r\n\t<li><strong>gate</strong>&nbsp;&ndash; brama</li>\r\n</ul>	9	1
